 3→import android.content.Context
 4→import android.media.MediaRecorder
 5→import android.os.Build
 6→import java.io.File
 7→
 8→class AudioRecorder(private val context: Context) {
 9→
10→    private var recorder: MediaRecorder? = null
11→    private var outputFile: File? = null
12→
13→    val isRecording: Boolean
14→        get() = recorder != null
15→
16→    fun start(): File {
17→        val file = File(context.cacheDir, "voice_${System.currentTimeMillis()}.m4a")
18→        outputFile = file
19→
20→        val mr = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
21→            MediaRecorder(context)
22→        } else {
23→            @Suppress("DEPRECATION")
24→            MediaRecorder()
25→        }
26→
27→        mr.apply {
28→            setAudioSource(MediaRecorder.AudioSource.MIC)
29→            setOutputFormat(MediaRecorder.OutputFormat.MPEG_4)
30→            setAudioEncoder(MediaRecorder.AudioEncoder.AAC)
31→            setAudioSamplingRate(44100)
32→            setAudioEncodingBitRate(128000)
33→            setOutputFile(file.absolutePath)
34→            prepare()
35→            start()
36→        }
37→
38→        recorder = mr
39→        return file
40→    }
41→
42→    fun stop(): File? {
43→        val file = outputFile
44→        try {
45→            recorder?.apply {
46→                stop()
47→                release()
48→            }
49→        } catch (_: RuntimeException) {
50→            // stop() can throw if called too quickly after start
51→            file?.delete()
52→            return null
53→        } finally {
54→            recorder = null
55→        }
56→        return file
57→    }
58→
59→    fun cancel() {
60→        try {
61→            recorder?.apply {
62→                stop()
63→                release()
64→            }
65→        } catch (_: RuntimeException) {
66→            // Ignore — may not have started properly
67→        } finally {
68→            recorder = null
69→            outputFile?.delete()
70→            outputFile = null
71→        }
72→    }
73→}
