 16→// requireAuth extracts auth claims from context or returns an error.
 17→// Returns a GraphQL error with extensions.code = "UNAUTHENTICATED" so clients
 18→// can detect auth failures in GraphQL responses (not just HTTP 401).
 19→func requireAuth(ctx context.Context) (*auth.Claims, error) {
 20→	claims := auth.GetClaims(ctx)
 21→	if claims == nil {
 22→		return nil, &gqlerror.Error{
 23→			Message:    "authentication required",
 24→			Extensions: map[string]any{"code": "UNAUTHENTICATED"},
 25→		}
 26→	}
 27→	return claims, nil
 28→}
