 30→// toGraphQLItem maps a domain Item to the GraphQL model Item.
 31→func toGraphQLItem(it *item.Item) *model.Item {
 32→	return &model.Item{
 33→		ID:           it.ID.String(),
 34→		Type:         model.ItemType(strings.ToUpper(it.Type)),
 35→		Status:       model.ItemStatus(strings.ToUpper(it.Status)),
 36→		Sensitivity:  model.SensitivityLevel(strings.ToUpper(it.Sensitivity)),
 37→		Title:        it.Title,
 38→		ContentText:  it.ContentText,
 39→		ContentURL:   it.ContentURL,
 40→		Tags:         ensureStringSlice(it.Tags),
 41→		Metadata:     ensureMap(it.Metadata),
 42→		AutoMetadata: ensureMap(it.AutoMetadata),
 43→		Source:       it.Source,
 44→		SourceURL:    it.SourceURL,
 45→		CreatedAt:    it.CreatedAt,
 46→		UpdatedAt:    it.UpdatedAt,
 47→		CapturedAt:   it.CapturedAt,
 48→	}
 49→}
