 51→// toGraphQLItems maps a slice of domain Items to GraphQL model Items.
 52→func toGraphQLItems(items []*item.Item) []*model.Item {
 53→	result := make([]*model.Item, len(items))
 54→	for i, it := range items {
 55→		result[i] = toGraphQLItem(it)
 56→	}
 57→	return result
 58→}
