 60→// toItemFilter converts a GraphQL ItemFilter to a domain Filter.
 61→func toItemFilter(f *model.ItemFilter) *item.Filter {
 62→	if f == nil {
 63→		return nil
 64→	}
 65→	result := &item.Filter{
 66→		Source: f.Source,
 67→	}
 68→	for _, t := range f.Types {
 69→		result.Types = append(result.Types, strings.ToLower(string(t)))
 70→	}
 71→	for _, s := range f.Status {
 72→		result.Status = append(result.Status, strings.ToLower(string(s)))
 73→	}
 74→	for _, s := range f.Sensitivity {
 75→		result.Sensitivity = append(result.Sensitivity, strings.ToLower(string(s)))
 76→	}
 77→	result.Tags = f.Tags
 78→	if f.DateFrom != nil {
 79→		result.DateFrom = f.DateFrom
 80→	}
 81→	if f.DateTo != nil {
 82→		result.DateTo = f.DateTo
 83→	}
 84→	return result
 85→}
