100→// Do sends a GraphQL request and decodes the response data into result.
101→func (c *Client) Do(ctx context.Context, query string, variables map[string]any, result any) error {
102→	body, err := json.Marshal(graphqlRequest{
103→		Query:     query,
104→		Variables: variables,
105→	})
106→	if err != nil {
107→		return fmt.Errorf("cli: marshal request: %w", err)
108→	}
109→
110→	req, err := http.NewRequestWithContext(ctx, http.MethodPost, c.apiURL+"/graphql", bytes.NewReader(body))
111→	if err != nil {
112→		return fmt.Errorf("cli: create request: %w", err)
113→	}
114→	req.Header.Set("Content-Type", "application/json")
115→	if c.token != "" {
116→		req.Header.Set("Authorization", "Bearer "+c.token)
117→	}
118→
119→	resp, err := c.httpClient.Do(req)
120→	if err != nil {
121→		return fmt.Errorf("cli: send request: %w", err)
122→	}
123→	defer func() { _ = resp.Body.Close() }()
124→
125→	respBody, err := io.ReadAll(resp.Body)
126→	if err != nil {
127→		return fmt.Errorf("cli: read response: %w", err)
128→	}
129→
130→	if resp.StatusCode == http.StatusUnauthorized {
131→		return fmt.Errorf("cli: not authenticated (run 'flotsam login' first)")
132→	}
133→	if resp.StatusCode != http.StatusOK {
134→		return fmt.Errorf("cli: unexpected status %d: %s", resp.StatusCode, string(respBody))
135→	}
136→
137→	var gqlResp graphqlResponse
138→	if err := json.Unmarshal(respBody, &gqlResp); err != nil {
139→		return fmt.Errorf("cli: parse response: %w", err)
140→	}
141→
142→	if len(gqlResp.Errors) > 0 {
143→		// Check if any error is an auth error via extensions.code.
144→		for _, e := range gqlResp.Errors {
145→			if code, _ := e.Extensions["code"].(string); code == "UNAUTHENTICATED" {
146→				return fmt.Errorf("cli: not authenticated (run 'flotsam login' first)")
147→			}
148→		}
149→		messages := make([]string, len(gqlResp.Errors))
150→		for i, e := range gqlResp.Errors {
151→			messages[i] = e.Message
152→		}
153→		return fmt.Errorf("cli: %s", strings.Join(messages, "; "))
154→	}
155→
156→	if result != nil {
157→		if err := json.Unmarshal(gqlResp.Data, result); err != nil {
158→			return fmt.Errorf("cli: decode data: %w", err)
159→		}
160→	}
161→
162→	return nil
163→}
