package com.flotsam.capture.network

import com.google.gson.Gson
import com.google.gson.JsonParser
import okhttp3.MediaType.Companion.toMediaType
import okhttp3.OkHttpClient
import okhttp3.Request
import okhttp3.RequestBody.Companion.toRequestBody
import java.io.IOException
import java.util.concurrent.TimeUnit

class GraphQLClient {

    private val client = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .build()

    private val gson = Gson()

    fun captureVoiceNote(
        audioKey: String,
        tags: List<String>,
        baseUrl: String,
        token: String,
    ): String {
        val tagsJson = tags.joinToString(", ") { "\"$it\"" }

        val query = """
            mutation CaptureVoiceNote(${'$'}input: VoiceNoteInput!) {
                captureVoiceNote(input: ${'$'}input) {
                    id
                    title
                    status
                }
            }
        """.trimIndent()

        val variables = mapOf(
            "input" to buildMap {
                put("audioKey", audioKey)
                put("source", "android_app")
                if (tags.isNotEmpty()) put("tags", tags)
            },
        )

        val payload = mapOf(
            "query" to query,
            "variables" to variables,
        )

        val body = gson.toJson(payload)
            .toRequestBody("application/json".toMediaType())

        val request = Request.Builder()
            .url("${baseUrl.trimEnd('/')}/graphql")
            .header("Authorization", "Bearer $token")
            .post(body)
            .build()

        val response = client.newCall(request).execute()
        if (!response.isSuccessful) {
            val errorBody = response.body?.string() ?: "Unknown error"
            if (response.code == 401) {
                throw AuthenticationException("Authentication failed — check your token in settings")
            }
            throw IOException("GraphQL request failed (${response.code}): $errorBody")
        }

        val responseBody = response.body?.string() ?: throw IOException("Empty response body")

        // Check for auth errors in GraphQL error extensions
        try {
            val json = JsonParser.parseString(responseBody).asJsonObject
            val errors = json.getAsJsonArray("errors")
            if (errors != null && errors.size() > 0) {
                for (err in errors) {
                    val code = err.asJsonObject
                        ?.getAsJsonObject("extensions")
                        ?.get("code")?.asString
                    if (code == "UNAUTHENTICATED" || code == "FORBIDDEN") {
                        throw AuthenticationException("Authentication failed — check your token in settings")
                    }
                }
            }
        } catch (e: AuthenticationException) {
            throw e
        } catch (_: Exception) {
            // JSON parsing failure — fall through and return raw body
        }

        return responseBody
    }
}

