package com.flotsam.capture.network

import okhttp3.mockwebserver.MockResponse
import okhttp3.mockwebserver.MockWebServer
import org.junit.After
import org.junit.Assert.assertEquals
import org.junit.Assert.assertTrue
import org.junit.Assert.fail
import org.junit.Before
import org.junit.Test
import java.io.IOException

class GraphQLClientTest {

    private lateinit var server: MockWebServer
    private lateinit var client: GraphQLClient

    @Before
    fun setUp() {
        server = MockWebServer()
        server.start()
        client = GraphQLClient()
    }

    @After
    fun tearDown() {
        server.shutdown()
    }

    private val baseUrl get() = server.url("/").toString().trimEnd('/')

    @Test
    fun `captureVoiceNote returns response body on success`() {
        val responseJson = """
            {
                "data": {
                    "captureVoiceNote": {
                        "id": "item_123",
                        "title": "Voice note",
                        "status": "active"
                    }
                }
            }
        """.trimIndent()

        server.enqueue(MockResponse().setBody(responseJson).setResponseCode(200))

        val result = client.captureVoiceNote("audio-key-1", listOf("tag1"), baseUrl, "valid-token")

        assertTrue(result.contains("item_123"))

        val request = server.takeRequest()
        assertEquals("Bearer valid-token", request.getHeader("Authorization"))
        assertTrue(request.body.readUtf8().contains("CaptureVoiceNote"))
    }

    @Test
    fun `captureVoiceNote throws AuthenticationException on HTTP 401`() {
        server.enqueue(MockResponse().setResponseCode(401).setBody("Unauthorized"))

        try {
            client.captureVoiceNote("audio-key-1", emptyList(), baseUrl, "bad-token")
            fail("Expected AuthenticationException")
        } catch (e: AuthenticationException) {
            assertTrue(e.message!!.contains("Authentication failed"))
        }
    }

    @Test
    fun `captureVoiceNote throws AuthenticationException on UNAUTHENTICATED error code`() {
        val responseJson = """
            {
                "data": null,
                "errors": [{
                    "message": "access denied",
                    "extensions": { "code": "UNAUTHENTICATED" }
                }]
            }
        """.trimIndent()

        server.enqueue(MockResponse().setBody(responseJson).setResponseCode(200))

        try {
            client.captureVoiceNote("audio-key-1", emptyList(), baseUrl, "expired-token")
            fail("Expected AuthenticationException")
        } catch (e: AuthenticationException) {
            assertTrue(e.message!!.contains("Authentication failed"))
        }
    }

    @Test
    fun `captureVoiceNote throws AuthenticationException on FORBIDDEN error code`() {
        val responseJson = """
            {
                "data": null,
                "errors": [{
                    "message": "forbidden",
                    "extensions": { "code": "FORBIDDEN" }
                }]
            }
        """.trimIndent()

        server.enqueue(MockResponse().setBody(responseJson).setResponseCode(200))

        try {
            client.captureVoiceNote("audio-key-1", emptyList(), baseUrl, "token")
            fail("Expected AuthenticationException")
        } catch (e: AuthenticationException) {
            assertTrue(e.message!!.contains("Authentication failed"))
        }
    }

    @Test
    fun `captureVoiceNote throws GraphQLException on non-auth error`() {
        val responseJson = """
            {
                "data": null,
                "errors": [{
                    "message": "resolver: capture voice note: audio key not found",
                    "extensions": { "code": "INTERNAL_ERROR" }
                }]
            }
        """.trimIndent()

        server.enqueue(MockResponse().setBody(responseJson).setResponseCode(200))

        try {
            client.captureVoiceNote("bad-key", emptyList(), baseUrl, "valid-token")
            fail("Expected GraphQLException")
        } catch (e: GraphQLException) {
            assertEquals("resolver: capture voice note: audio key not found", e.message)
        }
    }

    @Test
    fun `captureVoiceNote joins multiple error messages`() {
        val responseJson = """
            {
                "data": null,
                "errors": [
                    { "message": "field 'audioKey' is required" },
                    { "message": "field 'source' is required" }
                ]
            }
        """.trimIndent()

        server.enqueue(MockResponse().setBody(responseJson).setResponseCode(200))

        try {
            client.captureVoiceNote("", emptyList(), baseUrl, "valid-token")
            fail("Expected GraphQLException")
        } catch (e: GraphQLException) {
            assertEquals("field 'audioKey' is required; field 'source' is required", e.message)
        }
    }

    @Test
    fun `captureVoiceNote throws IOException on HTTP 500`() {
        server.enqueue(MockResponse().setResponseCode(500).setBody("Internal Server Error"))

        try {
            client.captureVoiceNote("audio-key-1", emptyList(), baseUrl, "valid-token")
            fail("Expected IOException")
        } catch (e: AuthenticationException) {
            fail("Should not be AuthenticationException for 500")
        } catch (e: IOException) {
            assertTrue(e.message!!.contains("500"))
        }
    }

    @Test
    fun `captureVoiceNote throws IOException on empty response body`() {
        server.enqueue(MockResponse().setResponseCode(200).setBody(""))

        try {
            client.captureVoiceNote("audio-key-1", emptyList(), baseUrl, "valid-token")
            fail("Expected exception")
        } catch (_: Exception) {
            // Empty body should cause a parse error or empty body exception
        }
    }

    @Test
    fun `captureVoiceNote sends tags in variables`() {
        val responseJson = """
            {
                "data": {
                    "captureVoiceNote": { "id": "1", "title": "test", "status": "active" }
                }
            }
        """.trimIndent()

        server.enqueue(MockResponse().setBody(responseJson).setResponseCode(200))

        client.captureVoiceNote("key", listOf("meeting", "important"), baseUrl, "token")

        val body = server.takeRequest().body.readUtf8()
        assertTrue(body.contains("meeting"))
        assertTrue(body.contains("important"))
    }
}

